import {
	Button,
	FieldError,
	Label,
	ListBox,
	ListBoxItem,
	Popover,
	Select as RACSelect,
	SelectValue,
	Text,
} from "react-aria-components"
import type { SelectItem } from "./select.schema"
import { getSelectStyles } from "./select.styles"

interface SelectProps {
	label?: string
	placeholder?: string
	items?: SelectItem[]
	value?: string
	defaultValue?: string
	isDisabled?: boolean
	isRequired?: boolean
	isInvalid?: boolean
	isOpen?: boolean
	defaultOpen?: boolean
	disabledKeys?: string[]
	validationBehavior?: "aria" | "native"
	validate?: (value: string) => string | string[] | true | null | undefined
	name?: string
	description?: string
	errorMessage?: string
	onChange?: (value: string) => void
	onOpenChange?: (isOpen: boolean) => void
}

export function Select({
	label,
	placeholder = "Select an option",
	items = [],
	value,
	defaultValue,
	isDisabled = false,
	isRequired = false,
	isInvalid = false,
	isOpen,
	defaultOpen,
	disabledKeys,
	validationBehavior,
	validate,
	name,
	description,
	errorMessage,
	onChange,
	onOpenChange,
}: SelectProps) {
	const styles = getSelectStyles()

	return (
		<RACSelect
			selectedKey={value}
			defaultSelectedKey={defaultValue}
			isDisabled={isDisabled}
			isRequired={isRequired}
			isInvalid={isInvalid}
			isOpen={isOpen}
			defaultOpen={defaultOpen}
			validationBehavior={validationBehavior}
			validate={validate ? (key) => validate(key as string) : undefined}
			name={name}
			placeholder={placeholder}
			onSelectionChange={(key) => onChange?.(key as string)}
			onOpenChange={onOpenChange}
			className={styles.field}
		>
			{label && <Label className={styles.label}>{label}</Label>}
			<Button className={({ isDisabled: dis }) => styles.trigger({ isDisabled: dis, isInvalid })}>
				<SelectValue>
					{({ selectedText, isPlaceholder }) => (
						<span className={isPlaceholder ? styles.placeholder : styles.value}>
							{isPlaceholder ? placeholder : selectedText}
						</span>
					)}
				</SelectValue>
				<svg
					aria-hidden="true"
					viewBox="0 0 16 16"
					fill="none"
					stroke="currentColor"
					strokeWidth={1.5}
					className={styles.chevron}
				>
					<path d="M4 6l4 4 4-4" strokeLinecap="round" strokeLinejoin="round" />
				</svg>
			</Button>
			{description && (
				<Text slot="description" className={styles.description}>
					{description}
				</Text>
			)}
			<FieldError className={styles.errorMessage}>{errorMessage}</FieldError>
			<Popover className={styles.popover}>
				<ListBox disabledKeys={disabledKeys} className={styles.listbox}>
					{items.map((item) => (
						<ListBoxItem key={item.value} id={item.value} isDisabled={item.isDisabled} className={styles.item}>
							{item.label}
						</ListBoxItem>
					))}
				</ListBox>
			</Popover>
		</RACSelect>
	)
}

interface TriggerState {
	isDisabled?: boolean
	isInvalid?: boolean
}

const triggerBase =
	"flex w-full min-w-40 min-h-11 cursor-pointer items-center justify-between gap-2 rounded border px-3 py-2 text-sm transition-colors"

export const getSelectStyles = () => ({
	field: "flex flex-col gap-1",
	label: "text-sm font-medium text-[var(--color-text)]",
	trigger({ isDisabled, isInvalid }: TriggerState) {
		if (isDisabled) {
			return `${triggerBase} cursor-not-allowed border-[var(--color-border)] bg-[var(--color-backgroundMuted)] opacity-50 text-[var(--color-textMuted)]`
		}
		if (isInvalid) {
			return `${triggerBase} border-[var(--color-danger)] bg-[var(--color-background)] text-[var(--color-text)]`
		}
		return `${triggerBase} border-[var(--color-border)] bg-[var(--color-background)] text-[var(--color-text)] hover:border-[var(--color-primary)]`
	},
	value: "flex-1 truncate text-left",
	placeholder: "text-[var(--color-textMuted)]",
	chevron: "h-4 w-4 shrink-0 text-[var(--color-textMuted)]",
	popover:
		"z-50 min-w-[var(--trigger-width)] rounded border border-[var(--color-border)] bg-[var(--color-background)] p-1 shadow-md",
	listbox: "max-h-64 overflow-auto outline-none",
	item: "flex cursor-pointer items-center rounded px-3 py-1.5 text-sm text-[var(--color-text)] outline-none transition-colors data-[disabled]:cursor-not-allowed data-[disabled]:opacity-50 data-[focused]:bg-[var(--color-backgroundMuted)] data-[selected]:font-medium data-[selected]:text-[var(--color-primary)]",
	description: "text-xs text-[var(--color-textMuted)]",
	errorMessage: "text-xs text-[var(--color-danger)]",
})
